/**
 * MedX columns layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Multi-column layouts for comparison tables.
 */
const COLUMNS_TOKENS = Object.freeze({
  primary: { value: "layout-columns-primary", scope: "layout" },
  secondary: { value: "layout-columns-secondary", scope: "layout" },
  muted: { value: "layout-columns-muted", scope: "layout" },
  accent: { value: "layout-columns-accent", scope: "layout" },
  surface: { value: "layout-columns-surface", scope: "layout" },
});

const COLUMNS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const COLUMNS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const columnsRegistry = new Map();
const COLUMNS_listeners = new Set();
let COLUMNS_seq = 0;

function createColumnsId(prefix = "medx-layout-columns") {
  COLUMNS_seq += 1;
  return `${prefix}-${COLUMNS_seq}`;
}

function registerColumns(config = {}) {
  const entryId = config.id ?? createColumnsId();
  const preset = COLUMNS_PRESETS[config.preset ?? "default"] ?? COLUMNS_PRESETS.default;
  const token = COLUMNS_TOKENS[config.token ?? preset.token] ?? COLUMNS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: COLUMNS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  columnsRegistry.set(entryId, entry);
  notifyColumnsListeners("register", entry);
  return entry;
}

function updateColumns(id, patch = {}) {
  const entry = columnsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyColumnsListeners("update", entry);
  return entry;
}

function resolveColumns(id) {
  const entry = columnsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listColumnsEntries(filter = {}) {
  let items = Array.from(columnsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onColumnsEvent(listener) {
  COLUMNS_listeners.add(listener);
  return () => COLUMNS_listeners.delete(listener);
}

function notifyColumnsListeners(type, entry) {
  for (const listener of COLUMNS_listeners) {
    try {
      listener({ type, entry, registrySize: columnsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:columns] listener error", err.message);
    }
  }
}

function getColumnsMetrics() {
  const items = listColumnsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(COLUMNS_TOKENS).length,
    presets: Object.keys(COLUMNS_PRESETS).length,
  };
}

async function runMedxColumns() {
  console.log("[medx:ui:layout:columns] runtime initialized");
  console.log(`[medx:ui:layout:columns] tokens=${Object.keys(COLUMNS_TOKENS).length} presets=${Object.keys(COLUMNS_PRESETS).length}`);

  const events = [];
  onColumnsEvent((e) => events.push(e.type));

  const domains = Object.keys(COLUMNS_SUPPLY_CHAIN);
  const presets = Object.keys(COLUMNS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerColumns({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/columns" },
    });
  }

  const first = listColumnsEntries()[0];
  if (first) updateColumns(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getColumnsMetrics();
  const resolved = first ? resolveColumns(first.id) : null;

  console.log(`[medx:ui:layout:columns] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:columns] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:columns] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:columns] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:columns] bootstrap complete");
}

module.exports = runMedxColumns;
